import React, { useState, useEffect } from "react";
import { Link, useLocation } from "react-router-dom";
import axios from "../utils/axios";
import { base_url } from "../utils/axiosConfig";

const logo = "/logo3.png";

function Navmobile() {
  const [isOpen, setIsOpen] = useState(false);
  const [isFixed, setIsFixed] = useState(false);
  const location = useLocation();

  const [categories, setCategories] = useState([]);

  useEffect(() => {
    const handleScroll = () => {
      setIsFixed(window.scrollY > 100);
    };

    const fetchCategories = async () => {
      try {
        const response = await axios.get(`${base_url}category`);
        // Limit to relevant categories if needed, or take all
        setCategories(response.data);
      } catch (error) {
        console.error("Error fetching categories:", error);
      }
    };

    window.addEventListener("scroll", handleScroll);
    fetchCategories();
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  const handleToggle = () => setIsOpen(!isOpen);

  const currentPath = location.pathname;

  return (
    <nav
      className={`sm:hidden md:fixed lg:fixed xl:fixed top-0 left-0 w-full z-20 transition-all duration-300 ease-in-out bg-white shadow-md ${
        isFixed ? "opacity-100" : "opacity-0"
      }`}
    >
      <div className="max-w-screen-xl flex flex-wrap items-center justify-between mx-auto p-4">
        <Link
          to="/"
          className="flex items-center space-x-3 rtl:space-x-reverse"
        >
          <img src={logo} className="h-20" alt="Logo" />
          <span className="self-center text-2xl font-semibold whitespace-nowrap">
            Pulse{" "}
            <span className="animate-pulse inline-block text-teal-600">
              Addis
            </span>{" "}
          </span>
        </Link>
        <button
          onClick={handleToggle}
          type="button"
          className="inline-flex items-center p-2 w-10 h-10 justify-center text-sm text-gray-500 rounded-lg  hover:bg-gray-100 focus:outline-none focus:ring-2 focus:ring-gray-200"
          aria-controls="navbar-dropdown"
          aria-expanded={isOpen}
        >
          <span className="sr-only">Open main menu</span>
          {isOpen ? (
            <span className="text-2xl">&times;</span>
          ) : (
            <svg
              className="w-5 h-5"
              aria-hidden="true"
              xmlns="http://www.w3.org/2000/svg"
              fill="none"
              viewBox="0 0 17 14"
            >
              <path
                stroke="currentColor"
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth="2"
                d="M1 1h15M1 7h15M1 13h15"
              />
            </svg>
          )}
        </button>
        <div
          className={`absolute top-full left-0 w-full bg-white shadow-2xl transition-all duration-300 origin-top border-t border-teal-50 rounded-b-2xl ${
            isOpen
              ? "opacity-100 scale-y-100 visible"
              : "opacity-0 scale-y-0 invisible"
          }`}
          id="navbar-dropdown"
        >
          <ul className="flex flex-col p-4 space-y-2 mt-2 max-h-[80vh] overflow-y-auto">
            {/* Primary Nav Items */}
            {[
              { to: "/", label: "Home", icon: <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m3 9 9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z" /><polyline points="9 22 9 12 15 12 15 22" /></svg> },
              { to: "/shop", label: "Shop", icon: <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8" /><line x1="21" y1="21" x2="16.65" y2="16.65" /></svg> },
              { to: "/category", label: "Category", icon: <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><rect width="7" height="7" x="3" y="3" rx="1" /><rect width="7" height="7" x="14" y="3" rx="1" /><rect width="7" height="7" x="14" y="14" rx="1" /><rect width="7" height="7" x="3" y="14" rx="1" /></svg> },
              { to: "/wishlist", label: "Saved", icon: <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M19 14c1.49-1.46 3-3.21 3-5.5A5.5 5.5 0 0 0 16.5 3c-1.76 0-3 .5-4.5 2-1.5-1.5-2.74-2-4.5-2A5.5 5.5 0 0 0 2 8.5c0 2.3 1.5 4.05 3 5.5l7 7Z" /></svg> },
              { to: "/care-suggestions", label: "Care Advice", icon: <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z"/></svg> },
              { to: "/special-offer", label: "Special Offers", icon: <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M6 2 3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4Z"/><line x1="3" y1="6" x2="21" y2="6"/><path d="M16 10a4 4 0 0 1-8 0"/></svg> },
              { to: "/myaccount", label: "Account", icon: <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" /><circle cx="12" cy="7" r="4" /></svg> },
            ].map((item) => (
              <li key={item.to}>
                <Link
                  to={item.to}
                  className={`flex items-center gap-3 py-3 px-4 rounded-xl transition-all ${
                    currentPath === item.to
                      ? "bg-teal-50 text-teal-600 font-bold"
                      : "text-gray-700 hover:bg-gray-50"
                  }`}
                  onClick={() => setIsOpen(false)}
                >
                  <span className={`${currentPath === item.to ? "text-teal-600" : "text-gray-400"}`}>
                    {item.icon}
                  </span>
                  {item.label}
                </Link>
              </li>
            ))}

            <div className="border-t border-gray-100 my-4"></div>
            <p className="px-4 text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-2">Popular Categories</p>
            
            {categories.slice(0, 8).map((cat, index) => {
              const title = cat.title || cat.name;
              const routes = {
                "Medicines": "/medicines",
                "OTC": "/otc",
                "Vitamins": "/vitamins",
                "Mother & Baby": "/mother-baby",
                "Prescription": "/medicines"
              };
              const targetPath = routes[title] || `/shop?category=${encodeURIComponent(title)}`;
              return (
                <li key={index}>
                  <Link
                    to={targetPath}
                    className="flex items-center gap-3 py-2.5 px-4 text-gray-600 hover:bg-teal-50 hover:text-teal-600 rounded-lg transition-colors"
                    onClick={() => setIsOpen(false)}
                  >
                    <span className="w-1.5 h-1.5 rounded-full bg-teal-400"></span>
                    {title}
                  </Link>
                </li>
              );
            })}

            <div className="border-t border-gray-100 my-4"></div>
            <li>
              <Link
                to="/login"
                className="block py-3 px-4 text-teal-600 font-bold hover:bg-teal-50 rounded-lg text-center border border-teal-100"
                onClick={() => setIsOpen(false)}
              >
                Sign In
              </Link>
            </li>
            <li className="pt-1">
              <Link
                to="/register"
                className="block py-3 px-4 bg-gray-900 text-white font-bold hover:bg-gray-800 rounded-lg text-center"
                onClick={() => setIsOpen(false)}
              >
                Create Account
              </Link>
            </li>
          </ul>
        </div>
      </div>
    </nav>
  );
}

export default Navmobile;
